"use client";

import { useState } from "react";
import type { ComponentPropsWithoutRef } from "react";

import { cn } from "@/lib/utils";

import { createCompoundContext } from "../_lib/compound";

interface EmailInputContextValue {
  error?: string;
  setValue: (value: string) => void;
  validateEmail: (value: string) => boolean;
  value: string;
}

const { Provider, useCompoundContext } =
  createCompoundContext<EmailInputContextValue>("EmailInput");

export interface EmailInputProps extends ComponentPropsWithoutRef<"div"> {
  defaultValue?: string;
  invalidMessage?: string;
  onValueChange?: (value: string) => void;
  validateEmail?: (value: string) => boolean;
}

function Input({ className, ...props }: ComponentPropsWithoutRef<"input">) {
  const { error, setValue, value } = useCompoundContext();
  return (
    <input
      type="email"
      value={value}
      aria-invalid={Boolean(error)}
      onChange={(event) => setValue(event.target.value)}
      className={cn(
        "w-full rounded-md border bg-background px-3 py-2 text-sm outline-none focus-visible:ring-2 focus-visible:ring-ring",
        error && "border-destructive",
        className
      )}
      placeholder="you@example.com"
      {...props}
    />
  );
}

function HelpText({
  className,
  children,
  ...props
}: ComponentPropsWithoutRef<"p">) {
  useCompoundContext();
  return (
    <p className={cn("text-xs text-muted-foreground", className)} {...props}>
      {children ?? "We’ll only use this address for your receipt."}
    </p>
  );
}

function ErrorMessage({
  className,
  children,
  ...props
}: ComponentPropsWithoutRef<"p">) {
  const { error } = useCompoundContext();
  if (!(children || error)) {
    return null;
  }
  return (
    <p
      role="alert"
      className={cn("text-xs text-destructive", className)}
      {...props}
    >
      {children ?? error}
    </p>
  );
}

function EmailInputRoot({
  defaultValue = "",
  invalidMessage = "Enter a valid email address.",
  onValueChange,
  validateEmail = (value) => /^\S+@\S+\.\S+$/.test(value),
  className,
  children,
  ...props
}: EmailInputProps) {
  const [value, updateValue] = useState(defaultValue);
  const error = value && !validateEmail(value) ? invalidMessage : undefined;
  const setValue = (next: string) => {
    updateValue(next);
    onValueChange?.(next);
  };
  return (
    <Provider value={{ error, setValue, validateEmail, value }}>
      <div
        className={cn(
          "w-full space-y-2 rounded-xl border bg-card p-4 sm:p-6",
          className
        )}
        {...props}
      >
        {children ?? (
          <>
            <Input />
            <HelpText />
            <ErrorMessage />
          </>
        )}
      </div>
    </Provider>
  );
}

export const EmailInput = Object.assign(EmailInputRoot, {
  ErrorMessage,
  HelpText,
  Input,
});

"use client";

import { createContext, createElement, useContext } from "react";
import type { ReactNode } from "react";

import { cn } from "@/lib/utils";

export interface CompoundProviderProps<T> {
  children: ReactNode;
  value: T;
}

export const createCompoundContext = <T,>(name: string) => {
  const Context = createContext<T | null>(null);

  const Provider = ({ value, children }: CompoundProviderProps<T>) =>
    createElement(Context.Provider, { value }, children);

  const useCompoundContext = () => {
    const context = useContext(Context);

    if (!context) {
      throw new Error(`${name} subcomponents must be rendered inside ${name}.`);
    }

    return context;
  };

  return { Provider, useCompoundContext };
};

export const formatPrice = (value: number, currency = "USD") =>
  new Intl.NumberFormat("en-US", {
    currency,
    style: "currency",
  }).format(value);

export type StepStatus = "completed" | "current" | "pending";

export interface TimelineStep {
  description?: string;
  label: string;
  status?: StepStatus;
}

export const statusClasses = (status: StepStatus = "pending") =>
  cn(
    "flex h-6 w-6 items-center justify-center rounded-full text-xs",
    status === "completed" && "bg-foreground text-background",
    status === "current" && "border-2 border-foreground bg-card",
    status === "pending" && "border border-muted-foreground/40 bg-card"
  );

export interface AddressValue {
  city?: string;
  country?: string;
  state?: string;
  street?: string;
  zip?: string;
}

export interface CountryOption {
  callingCode?: string;
  code: string;
  label: string;
}

export type FieldValidator<T> = (value: T) => boolean;
